svg.script:
// Core State
let collectiveInput = 0; // 0 (min) to 1 (max)
let isDragging = false;

// Physics / Smoothing state
let currentAlt = 0; // mapped to Y offset for the helicopter side view

// Base physics constants
const BASE_PITCH = 2; // degrees
const PITCH_RANGE = 12; // max pitch = 14 degrees

// Get Elements
const svgRoot = document.documentElement;
const stickHitbox = document.getElementById('stickHitbox');
const stickKnob = document.getElementById('stickKnob');
const resetBtnBg = document.getElementById('resetBtnBg');
const resetBtnText = document.getElementById('resetBtnText');

const pitchValueText = document.getElementById('pitchValueText');
const liftValueText = document.getElementById('liftValueText');

const airfoilSystem = document.getElementById('airfoilSystem');
const aoaArc = document.getElementById('aoaArc');
const liftVector = document.getElementById('liftVector');
const dragVector = document.getElementById('dragVector');
const liftLabel = document.getElementById('liftLabel');
const dragLabel = document.getElementById('dragLabel');

const heliSide = document.getElementById('heliSide');
const coneLeft = document.getElementById('coneLeft');
const coneRight = document.getElementById('coneRight');
const coneArc = document.getElementById('coneArc');

const torqueArrow = document.getElementById('torqueArrow');
const antiTorqueArrow = document.getElementById('antiTorqueArrow');

// Geometry Helpers
function getArcPath(x, y, radius, startAngle, endAngle) {
  const svgStart = (startAngle - 90) * Math.PI / 180.0;
  const svgEnd = (endAngle - 90) * Math.PI / 180.0;
  const startX = x + radius * Math.cos(svgStart);
  const startY = y + radius * Math.sin(svgStart);
  const endX = x + radius * Math.cos(svgEnd);
  const endY = y + radius * Math.sin(svgEnd);

  // Determine if arc is > 180 degrees
  const largeArcFlag = endAngle - startAngle <= 180 ? "0" : "1";
  return `M ${startX} ${startY} A ${radius} ${radius} 0 ${largeArcFlag} 1 ${endX} ${endY}`;
}

// Input Handling
function getMouseY(e) {
  let clientY = e.clientY;
  if (e.touches && e.touches.length > 0) {
    clientY = e.touches[0].clientY;
  }
  const pt = svgRoot.createSVGPoint();
  pt.x = 0; pt.y = clientY;
  const ctm = stickHitbox.getScreenCTM().inverse();
  return pt.matrixTransform(ctm).y;
}

function startDrag(e) {
  e.preventDefault();
  isDragging = true;
  updateLever(e);
}

function drag(e) {
  if (!isDragging) return;
  e.preventDefault();
  updateLever(e);
}

function stopDrag() {
  isDragging = false;
}

function resetLever() {
  collectiveInput = 0;
}

function updateLever(e) {
  let y = getMouseY(e);
  // Track is from y=15 to y=235 (height 220)
  // We map y=235 -> collective=0, y=15 -> collective=1
  let val = 1 - ((y - 15) / 220);
  collectiveInput = Math.max(0, Math.min(1, val));
}

// Attach Listeners
stickHitbox.addEventListener('mousedown', startDrag);
stickHitbox.addEventListener('touchstart', startDrag, {passive: false});
window.addEventListener('mousemove', drag);
window.addEventListener('touchmove', drag, {passive: false});
window.addEventListener('mouseup', stopDrag);
window.addEventListener('touchend', stopDrag);

resetBtnBg.addEventListener('click', resetLever);
resetBtnText.addEventListener('click', resetLever);

// Main Update Loop
function animate() {
  // 1. Calculate physics variables based on input
  const currentPitch = BASE_PITCH + (collectiveInput * PITCH_RANGE);

  // Simplified lift model: lift increases linearly with pitch/collective.
  // Offset by "weight" so it hovers around collective=0.4 (approx).
  // We'll normalize "lift" for visual purposes: 0% to 100%.
  const visualLift = (collectiveInput * 100); 

  // Drag increases quadratically with pitch (induced drag)
  const baseDrag = 10;
  const inducedDrag = Math.pow(currentPitch, 2) * 0.4;
  const totalDrag = baseDrag + inducedDrag;

  // Torque is proportional to drag
  const torqueScale = totalDrag * 0.5;

  // 2. Update UI Lever visual
  const knobY = 235 - (collectiveInput * 220);
  stickKnob.setAttribute('transform', `translate(0, ${knobY})`);

  pitchValueText.textContent = currentPitch.toFixed(1) + '°';
  liftValueText.textContent = visualLift.toFixed(0) + ' %';
  // Change color based on "hover" threshold (approx 40%)
  liftValueText.setAttribute('fill', visualLift > 40 ? '#0ea5e9' : '#94a3b8');

  // 3. Update Airfoil Visuals
  // Airfoil rotates CCW (negative angle in SVG) to pitch up
  airfoilSystem.setAttribute('transform', `rotate(${-currentPitch})`);

  // Draw AoA arc between horizontal (0) and chord line (-currentPitch)
  // Since SVG 0 is UP in getArcPath, horizontal is 90, pitched up is 90 - currentPitch
  if (currentPitch > 0) {
    aoaArc.setAttribute('d', getArcPath(0, 0, 80, 90 - currentPitch, 90));
  } else {
    aoaArc.setAttribute('d', '');
  }

  // Lift Vector (Grows vertically)
  const liftLength = 20 + (collectiveInput * 140);
  liftVector.setAttribute('y2', -liftLength);
  liftLabel.setAttribute('y', -liftLength - 10);

  // Drag Vector (Grows horizontally quadratically)
  const dragLength = 20 + (collectiveInput * collectiveInput * 100);
  dragVector.setAttribute('x2', dragLength);
  dragLabel.setAttribute('x', dragLength + 10);

  // 4. Update Helicopter Altitude View
  // Target altitude: Y offset from 150 (ground) to 30 (max height)
  // Hover is around Y=100
  let targetAlt = 150;
  if (collectiveInput > 0.3) {
     // Map 0.3-1.0 to Y 150 to 20
     let flyPercent = (collectiveInput - 0.3) / 0.7;
     targetAlt = 150 - (flyPercent * 130);
  }
  // Smooth interpolation for realistic feeling
  currentAlt += (targetAlt - currentAlt) * 0.05;
  heliSide.setAttribute('transform', `translate(0, ${currentAlt})`);

  // 5. Update Blade Coning View
  // Coning angle maxes out around 6 degrees
  const coningAngle = collectiveInput * 6;
  coneLeft.setAttribute('transform', `rotate(${coningAngle}, -10, -40)`);
  coneRight.setAttribute('transform', `rotate(${-coningAngle}, 10, -40)`);

  // 6. Update Torque View
  // Draw a curved arrow proportional to torque
  // Base radius = 30, grows slightly, sweeps further
  const sweepAngle = 30 + (collectiveInput * collectiveInput * 90); 
  torqueArrow.setAttribute('d', getArcPath(0, 10, 30, 180, 180 + sweepAngle));

  // Tail rotor arrow grows to counter torque
  const trLength = 10 + (collectiveInput * collectiveInput * 40);
  antiTorqueArrow.setAttribute('x2', -8 - trLength);

  requestAnimationFrame(animate);
}

// Start Loop
requestAnimationFrame(animate);
